CODE_EXAMPLE:
// Config at high level
public class AppConfig {
    public static final double STANDARD_DISCOUNT_RATE = 0.15;
}

// Low-level code receives the value
class PricingEngine {
    private final double discountRate;
    public PricingEngine(double discountRate) { this.discountRate = discountRate; }
    public double applyDiscount(double price) { return price * (1.0 - discountRate); }
}

// Wired at startup
new PricingEngine(AppConfig.STANDARD_DISCOUNT_RATE);

UNIT_TEST_EXAMPLE:
@Test
public void applyDiscount_reducesPrice() {
    PricingEngine engine = new PricingEngine(0.15);
    assertEquals(85.0, engine.applyDiscount(100.0), 0.001);
}

@Test
public void applyDiscount_usesInjectedRate() {
    PricingEngine engine = new PricingEngine(0.20);
    assertEquals(80.0, engine.applyDiscount(100.0), 0.001);
}
